function userInitials(name){
  return String(name || 'User').split(/\s+/).filter(Boolean).slice(0,2).map(x=>x[0]).join('').toUpperCase()
}


function normalizeAdvisorMatchName(name){
  let value = String(name || '').trim().toLowerCase().replace(/\s+/g,' ')
  if(value.includes(',')){
    const parts = value.split(',').map(x=>x.trim()).filter(Boolean)
    if(parts.length >= 2){
      value = `${parts[1]} ${parts[0]}`
    }
  }
  return value.replace(/[^a-z0-9 ]/g,'').replace(/\s+/g,' ').trim()
}

function isSameAdvisorName(a,b){
  return normalizeAdvisorMatchName(a) === normalizeAdvisorMatchName(b)
}

function filterByAdvisor(rows = [], advisorName = '') {
  if(!advisorName) return rows
  return rows.filter(r => {
    const candidate = r.advisor || r.service_advisor || r.advisor_name || r.writer || r.writer_name || ''
    return isSameAdvisorName(candidate, advisorName)
  })
}

const BRAND_LOGO_DATA = 'data:image/png;base64,'

const STATUSES = ['Complete','Committed','Unresponsive','Issue','Disposition Only']
const CONTACT_METHODS = ['','Phone','Email','Text','In Person']


function fileToDataUrl(file){
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => resolve(reader.result)
    reader.onerror = reject
    reader.readAsDataURL(file)
  })
}

function initials(name=''){
  const p=name.trim().split(' ')
  return ((p[0]?.[0]||'')+(p[1]?.[0]||'')).toUpperCase()
}
function statusClass(s){
  if(s==='Complete') return 'b-complete'
  if(s==='Committed') return 'b-committed'
  if(s==='Unresponsive') return 'b-unresponsive'
  if(s==='Issue') return 'b-issue'
  if(s==='Disposition Only') return 'b-disposition'
  return ''
}
function matchClass(s){
  if(s==='Matched') return 'b-match'
  if(s==='Disposition Only') return 'b-missing'
  if(s==='Follow-Up Only') return 'b-follow'
  return ''
}
function parseNum(v){
  const n = Number(String(v ?? '').replace('%','').replace(',','').trim())
  return Number.isFinite(n) ? n : 0
}
function titleCaseAdvisor(name){
  return String(name || '').trim().replace(/\s+/g, ' ').toLowerCase().replace(/\b\w/g, c => c.toUpperCase())
}

function canonicalAdvisorName(name){
  return titleCaseAdvisor(name)
}
function excelDateToIso(value){
  if(!value) return null
  if(value instanceof Date && !Number.isNaN(value.getTime())) return value.toISOString().slice(0,10)
  if(typeof value === 'number'){
    const date = XLSX.SSF.parse_date_code(value)
    if(!date) return null
    return `${date.y}-${String(date.m).padStart(2,'0')}-${String(date.d).padStart(2,'0')}`
  }
  const d = new Date(value)
  if(!Number.isNaN(d.getTime())) return d.toISOString().slice(0,10)
  return null
}
function estimateNpsDistribution(completed, nps){
  const total = Number(completed || 0)
  const net = Math.round((Number(nps || 0) / 100) * total)
  let promoters = 0, detractors = 0, passives = total
  if(net >= 0){ promoters = Math.min(total, net); passives = Math.max(0, total - promoters) }
  else { detractors = Math.min(total, Math.abs(net)); passives = Math.max(0, total - detractors) }
  return { promoters, passives, detractors }
}
function parseCsiWorkbook(workbook){
  const ws = workbook.Sheets['Table1'] || workbook.Sheets[workbook.SheetNames[0]]
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  let metrics = { national_score: 86.42, region_score: 83.2, store_nps: 69.23 }
  const advisorRows = []
  for (const row of raw) {
    const name = String(row[0] ?? '').trim()
    const nps = parseNum(row[1])
    const completed = parseNum(row[2])
    const impact = parseNum(row[4])
    if (!name) continue
    const lower = name.toLowerCase()
    if (lower === 'national') { metrics.national_score = nps; continue }
    if (lower === 'ce') { metrics.region_score = nps; continue }
    if (lower === 'mo027' || lower.includes('napleton')) { metrics.store_nps = nps; continue }
    if (lower === 'ce04') continue
    if (!/[a-zA-Z]/.test(name) || completed <= 0) continue
    const dist = estimateNpsDistribution(completed, nps)
    advisorRows.push({ advisor: canonicalAdvisorName(name), nps, completed_surveys: completed, promoters: dist.promoters, passives: dist.passives, detractors: dist.detractors, impact })
  }
  return { advisorRows, metrics }
}
function parseDispositionWorkbook(workbook){
  const ws = workbook.Sheets['Table'] || workbook.Sheets[workbook.SheetNames[0]]
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })
  return rows.map((r) => ({
    ro_number: String(r['RO Number'] ?? '').trim(),
    customer_name: String(r['Customer Name'] ?? '').trim(),
    customer_email: String(r['Customer Email'] ?? r['Email'] ?? r['Email Address'] ?? '').trim(),
    advisor: canonicalAdvisorName(r['Service Consultant Name'] ?? ''),
    ro_date: excelDateToIso(r['RO Date']),
    survey_status: String(r['Survey Status'] ?? '').trim(),
    response_date: excelDateToIso(r['Response Date']),
    invitation_id: String(r['Invitation ID'] ?? '').trim(),
    survey_id: String(r['Survey Id'] ?? r['Survey ID'] ?? '').trim(),
  })).filter(r => r.ro_number || r.customer_name)
}

function parseSurveyResultsWorkbook(workbook){
  const ws = workbook.Sheets['Table'] || workbook.Sheets[workbook.SheetNames[0]]
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })

  return rows.map((r) => ({
    survey_id: String(r['Survey ID'] ?? '').trim(),
    customer_name: String(r['Name'] ?? r['Customer Name'] ?? '').trim(),
    ro_number: String(r['Repair Order Number'] ?? r['RO Number'] ?? '').trim().replace(/\.0$/, ''),
    advisor: canonicalAdvisorName(r['Service Consultant Name'] ?? ''),
    response_date: excelDateToIso(r['Response Date']),
    survey_status: String(r['Survey Status'] ?? '').trim(),
    ksi: parseNum(r['Kia Service Index (KSI)']),
    likelihood_to_recommend: parseNum(r['Likelihood to Recommend (Dealer)']),
    vin: String(r['VIN'] ?? '').trim(),
    email: String(r['Email'] ?? '').trim(),
  })).filter(r => r.ro_number || r.customer_name || r.survey_id)
}




function parseFollowUpWorkbook(workbook){
  const ws = workbook.Sheets['Survey Data'] || workbook.Sheets[workbook.SheetNames[0]]
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })

  return rows.map((r) => {
    const rawStatus = String(r['Status'] ?? '').trim()
    const status = rawStatus || 'Committed'
    const rawRo = String(r['RO #'] ?? '').trim()
    const roNumber = /^\d+$/.test(rawRo) ? rawRo : ''
    const surveyCode = rawRo && !/^\d+$/.test(rawRo) ? rawRo : ''

    const notes = String(r['Notes'] ?? '').trim()
    const followUpDate = excelDateToIso(r['Follow-Up Date'])
    const noteWithFollowUp = [notes, followUpDate ? `Follow-Up Date: ${followUpDate}` : ''].filter(Boolean).join(' | ')

    return {
      customer_name: String(r['Customer Name'] ?? '').trim(),
      status,
      follow_up_category: status,
      survey_code: surveyCode,
      ro_number: roNumber,
      date_contacted: excelDateToIso(r['Contact Date']),
      contact_method: null,
      customer_response: null,
      follow_up_needed: status !== 'Complete',
      manager_notes: noteWithFollowUp || null,
      advisor: canonicalAdvisorName(r['Advisor'] ?? ''),
    }
  }).filter(r => r.customer_name || r.survey_code || r.ro_number)
}


function cleanRoDisplay(value){
  const raw = String(value ?? '').trim()
  if(!raw) return '—'
  return raw.replace(/\.0$/, '')
}

function getSortableValue(row, key){
  const value = row[key]
  if(key === 'took_survey') return value ? 1 : 0
  if(key === 'ro_number'){
    const raw = String(value ?? '').trim().replace(/\.0$/, '')
    const digits = raw.replace(/\D/g, '')
    return digits ? Number(digits) : raw.toLowerCase()
  }
  if(key === 'date_contacted' || key === 'response_date'){
    const date = new Date(value || '')
    return Number.isNaN(date.getTime()) ? 0 : date.getTime()
  }
  return String(value ?? '').toLowerCase()
}

function SortHeader({ label, column, sortConfig, onSort }){
  const active = sortConfig.key === column
  const arrow = !active ? '↕' : sortConfig.direction === 'asc' ? '↑' : '↓'
  return (
    <button className={`sort-header ${active ? 'active' : ''}`} onClick={() => onSort(column)}>
      {label} <span>{arrow}</span>
    </button>
  )
}


function surveyScoreClass(score){
  const n = Number(score)
  if(!Number.isFinite(n)) return ''
  if(n >= 9) return 'green'
  if(n >= 7) return 'orange'
  return 'red'
}

function formatSurveyScore(score){
  if(score === null || score === undefined || score === '') return '—'
  const n = Number(score)
  return Number.isFinite(n) ? n : score
}

function KpiCards({stats = {}, activeFilter, onFilterChange}){
  if(!stats) return <div className="grid">{Array.from({length:8}).map((_,i)=><div key={i} className="card"><div className="label">Loading</div></div>)}</div>
  const cards = [
    {key:'nps', label:'Store NPS', value:fmt(stats.nps_score), cls:npsClass(stats.nps_score), desc:`Region ${stats.region_score ?? REGION_NPS}`},
    {key:'region', label:'Region', value:stats.region_score, cls:'blue', desc:'Benchmark'},
    {key:'national', label:'National Score', value:stats.national_score, cls:'purple', desc:'National benchmark'},
    {key:'Disposition Only', label:'Disposition Only', value:stats.disposition_only, cls:'cyan', desc:'Surveyed, no follow-up', filter:true},
    {key:'Complete', label:'Complete', value:stats.complete, cls:'green', desc:'Follow-up complete', filter:true},
    {key:'Committed', label:'Committed', value:stats.committed, cls:'blue', desc:'Will respond', filter:true},
    {key:'Unresponsive', label:'Unresponsive', value:stats.unresponsive, cls:'red', desc:'No contact made', filter:true},
    {key:'Issue', label:'Issues', value:stats.issues, cls:'orange', desc:'Needs attention', filter:true},
  ]

  return <div className="grid">{cards.map(c=><div key={c.key} onClick={()=>c.filter && onFilterChange(activeFilter===c.key?'All':c.key)} className="card" style={{cursor:c.filter?'pointer':'default', outline:activeFilter===c.key?'1px solid currentColor':'none'}}>
    <div className="metric-card-top"><MetricIcon type={c.key === 'nps' ? 'nps' : c.key === 'region' ? 'region' : c.key === 'national' ? 'national' : c.key === 'Disposition Only' ? 'disposition' : c.key === 'Complete' ? 'complete' : c.key === 'Committed' ? 'committed' : c.key === 'Unresponsive' ? 'unresponsive' : 'issue'} /><div><div className="label">{c.label}</div><div className={`value ${c.cls}`}>{c.value}</div><div className="desc">{c.desc}</div></div></div>
  </div>)}</div>
}

function AdvisorLeaderboard({advisors=[], onPhotoSaved, onAdvisorClick}){
  async function handlePhotoUpload(advisor, file){
    if(!file) return
    const dataUrl = await fileToDataUrl(file)
    await saveAdvisorPhoto(advisor, dataUrl)
    onPhotoSaved?.()
  }

  return <div className="panel">
    <div className="panel-head">
      <div className="panel-title"><Trophy size={16} color="#facc15"/> Advisor Leaderboard</div>
      <div className="small">Click advisor photo/initials to upload picture</div>
    </div>
    <table>
      <thead>
        <tr>
          <th>Rank</th>
          <th>Advisor</th>
          <th>Final CSI / NPS</th>
          <th>Completed</th>
          <th>Promoters*</th>
          <th>Passives*</th>
          <th>Detractors*</th>
          <th>Impact</th>
        </tr>
      </thead>
      <tbody>{advisors.map((a,i)=>{
        const cls=npsClass(a.nps_score)
        return <tr key={a.advisor}>
          <td>{i===0?'🥇':i===1?'🥈':i===2?'🥉':`#${i+1}`}</td>
          <td>
            <div className="advisor-cell">
              <label className="avatar-upload-label" title="Click to upload/change advisor photo">
                {a.photo_data
                  ? <img className="advisor-photo" src={a.photo_data} alt={a.advisor}/>
                  : <div className="avatar">{initials(a.advisor)}</div>
                }
                <span className="camera-overlay">📷</span>
                <input type="file" accept="image/*" onChange={(e)=>handlePhotoUpload(a.advisor, e.target.files?.[0])}/>
              </label>
              <button className="advisor-link" onClick={()=>onAdvisorClick?.(a)}>{a.advisor}</button>
            </div>
          </td>
          <td><div className="bar-wrap"><div className="bar-bg"><div className="bar" style={{width:`${Math.max(0,Math.min(100,a.nps_score))}%`, background: cls==='green'?'var(--green)':cls==='orange'?'var(--orange)':'var(--red)'}} /></div><b className={cls}>{fmt(a.nps_score)}</b></div></td>
          <td><span className="pill" style={{background:'rgba(255,255,255,.08)'}}>{a.completed_surveys}</span></td>
          <td><span className="pill green" style={{background:'rgba(52,211,153,.14)'}}>{a.promoters}</span></td>
          <td><span className="pill orange" style={{background:'rgba(251,146,60,.14)'}}>{a.passives}</span></td>
          <td><span className="pill red" style={{background:'rgba(248,113,113,.14)'}}>{a.detractors}</span></td>
          <td className={a.impact>0?'green':a.impact<0?'red':''}>{a.impact>0?`+${a.impact}`:a.impact}</td>
        </tr>
      })}</tbody>
    </table>
    <div className="footer"><span>NPS source: Kia CSI Excel → service_ranker</span><span>Photos save to Supabase</span></div>
  </div>
}

function exportRows(rows){
  const ws = XLSX.utils.json_to_sheet(rows)
  const wb = XLSX.utils.book_new()
  XLSX.utils.book_append_sheet(wb, ws, 'Follow-Up Center')
  XLSX.writeFile(wb, `NapletonKia_FollowUp_${new Date().toISOString().slice(0,10)}.xlsx`)
}

function FollowUpTable({records,totalRecords,loading,activeFilter,onFilterChange,onSaved}){
  const [search,setSearch]=useState('')
  const [page,setPage]=useState(1)
  const [pageSize,setPageSize]=useState(25)
  const [edit,setEdit]=useState(null)
  const [advisorFilter,setAdvisorFilter]=useState('All Advisors')
  const [sortConfig,setSortConfig]=useState({ key: 'customer_name', direction: 'asc' })

  function handleSort(key){
    setSortConfig((current) => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }))
  }

  const advisorOptions = useMemo(() => {
    const names = Array.from(new Set(records.map(r => canonicalAdvisorName(r.advisor || '').trim()).filter(Boolean)))
    return ['All Advisors', ...names.sort((a,b)=>a.localeCompare(b))]
  }, [records])

  const filtered = useMemo(()=>{
    const q=search.toLowerCase()
    const baseRows = records
      .filter(r => advisorFilter === 'All Advisors' || canonicalAdvisorName(r.advisor || '') === advisorFilter)
      .filter(r=>Object.values(r).join(' ').toLowerCase().includes(q))
    return [...baseRows].sort((a,b)=>{
      const av = getSortableValue(a, sortConfig.key)
      const bv = getSortableValue(b, sortConfig.key)

      if(typeof av === 'number' && typeof bv === 'number'){
        return sortConfig.direction === 'asc' ? av - bv : bv - av
      }

      const result = String(av).localeCompare(String(bv), undefined, { numeric: true, sensitivity: 'base' })
      return sortConfig.direction === 'asc' ? result : -result
    })
  },[records,search,sortConfig,advisorFilter])
  const pageRows=filtered.slice((page-1)*pageSize,page*pageSize)
  const pages=Math.max(1,Math.ceil(filtered.length/pageSize))
  useEffect(()=>setPage(1),[activeFilter, search, pageSize, advisorFilter])
  async function save(){ await updateSurveyRecord(edit); setEdit(null); onSaved() }
  const val=(r,k)=> edit?.id===r.id ? edit[k] : r[k]
  const set=(k,v)=>setEdit(e=>({...e,[k]:v}))
  return <div className="panel">
    <div className="panel-head"><div><b>Follow-Up Center</b> <span className="small">{filtered.length} showing</span> <span className="small"><Database size={12}/> {totalRecords.toLocaleString()} total</span>{activeFilter === 'Complete' && <span className="completed-survey-note">Completed rows show survey results when matched by RO or customer name</span>}</div>
      <div style={{display:'flex',gap:8, flexWrap:'wrap'}}>
      <select className="advisor-filter" value={advisorFilter} onChange={e=>setAdvisorFilter(e.target.value)}>
        {advisorOptions.map(name => <option key={name} value={name}>{name}</option>)}
      </select>
      <input className="search" placeholder="Search..." value={search} onChange={e=>setSearch(e.target.value)}/>
      <button className="btn" onClick={()=>exportRows(filtered)}><Download size={14}/> Export</button>
    </div></div>
    <div className="tabs">{['All','Disposition Only','Complete','Committed','Unresponsive','Issue'].map(t=><button key={t} onClick={()=>onFilterChange(t)} className={`tab ${activeFilter===t?'active':''}`}>{t==='All'?'All Records':t}</button>)}</div>
    <div className="table-wrap"><table><thead><tr>
      <th><SortHeader label="Customer" column="customer_name" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Advisor" column="advisor" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Status" column="follow_up_category" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Disposition Match" column="disposition_match" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Commitment" column="commitment_status" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Took Survey" column="took_survey" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Survey Score" column="survey_score" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="KSI" column="survey_ksi" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="RO Number" column="ro_number" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Survey Status" column="disposition_survey_status" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Response Date" column="response_date" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th><SortHeader label="Date Contacted" column="date_contacted" sortConfig={sortConfig} onSort={handleSort}/></th>
      <th>Contact Method</th><th>Customer Response</th><th>Follow Up</th><th>Manager Notes</th><th></th></tr></thead>
    <tbody>{loading?<tr><td colSpan="14">Loading...</td></tr>:pageRows.map(r=>{
      const editing=edit?.id===r.id
      const status=val(r,'follow_up_category') || r.status
      return <tr key={r.id} className={r.synthetic ? 'synthetic-row' : ''}>
        <td><b>{r.customer_name}</b></td><td>{canonicalAdvisorName(r.advisor)}</td>
        <td>{editing?<select value={status||''} onChange={e=>set('follow_up_category',e.target.value)}>{STATUSES.map(s=><option key={s}>{s}</option>)}</select>:<span className={`badge ${statusClass(status)}`}>{status}</span>}</td>
        <td><span className={`badge ${matchClass(r.disposition_match)}`}>{r.disposition_match || '—'}</span></td>
        <td>{r.commitment_status || '—'}</td>
        <td>{r.took_survey ? <span className="badge b-complete">Yes</span> : <span className="badge b-missing">No</span>}</td>
        <td><span className={`survey-score-pill ${surveyScoreClass(r.survey_score)}`}>{formatSurveyScore(r.survey_score)}</span></td>
        <td>{r.survey_ksi ?? '—'}</td>
        <td>{cleanRoDisplay(r.ro_number)}</td>
        <td>{r.disposition_survey_status||'—'}</td>
        <td>{r.response_date||'—'}</td>
        <td>{editing?<input type="date" value={val(r,'date_contacted')||''} onChange={e=>set('date_contacted',e.target.value)}/>:r.date_contacted||'—'}</td>
        <td>{editing?<select value={val(r,'contact_method')||''} onChange={e=>set('contact_method',e.target.value)}>{CONTACT_METHODS.map(s=><option key={s}>{s}</option>)}</select>:r.contact_method||'—'}</td>
        <td>{editing?<textarea value={val(r,'customer_response')||''} onChange={e=>set('customer_response',e.target.value)}/>:r.customer_response||'—'}</td>
        <td>{editing?<input type="checkbox" checked={!!val(r,'follow_up_needed')} onChange={e=>set('follow_up_needed',e.target.checked)}/>:r.follow_up_needed?'Yes':'No'}</td>
        <td>{editing?<textarea value={val(r,'manager_notes')||''} onChange={e=>set('manager_notes',e.target.value)}/>:r.manager_notes||'—'}</td>
        <td>{r.synthetic ? <span className="small">Needs follow-up</span> : editing?<div className="row-actions"><button className="btn" onClick={save}><Save size={14}/> Save</button><button className="btn" onClick={()=>setEdit(null)}><X size={14}/></button></div>:<button className="btn" title="Edit follow-up row" onClick={()=>setEdit({...r})}><Edit2 size={14}/> Edit</button>}</td>
      </tr>
    })}</tbody></table></div>
    <div className="footer"><span>{filtered.length} records {activeFilter!=='All'?`· filtered by "${activeFilter}"`:''}</span><span><select value={pageSize} onChange={e=>setPageSize(Number(e.target.value))}>{[10,25,50,100].map(s=><option key={s}>{s}</option>)}</select> <button className="btn" disabled={page<=1} onClick={()=>setPage(p=>p-1)}>Prev</button> Page {page} of {pages} <button className="btn" disabled={page>=pages} onClick={()=>setPage(p=>p+1)}>Next</button></span></div>
  </div>
}


