function safeDateKey(value){
  if(!value) return null
  const d = new Date(value)
  if(Number.isNaN(d.getTime())) return null
  return d.toISOString().slice(0,10)
}

function shortDateLabel(key){
  if(!key) return ''
  const d = new Date(`${key}T00:00:00`)
  if(Number.isNaN(d.getTime())) return key
  return d.toLocaleDateString(undefined, { month: 'short', day: 'numeric' })
}

function buildFollowupTrend(records = []){
  const buckets = new Map()

  records.forEach((r) => {
    const key = safeDateKey(r.date_contacted) || safeDateKey(r.updated_at) || safeDateKey(r.created_at)
    if(!key) return
    if(!buckets.has(key)) buckets.set(key, { date: key, total: 0, completed: 0 })
    const bucket = buckets.get(key)
    bucket.total += 1
    if((r.follow_up_category || r.status) === 'Complete') bucket.completed += 1
  })

  return Array.from(buckets.values()).sort((a,b)=>a.date.localeCompare(b.date)).slice(-21)
}

function buildTeamPerformance(records = []){
  const map = new Map()

  records.forEach((r) => {
    const advisor = String(r.advisor || 'No Advisor').trim() || 'No Advisor'
    if(!map.has(advisor)) map.set(advisor, { advisor, completed: 0, incomplete: 0, total: 0 })
    const row = map.get(advisor)
    row.total += 1
    if((r.follow_up_category || r.status) === 'Complete') row.completed += 1
    else row.incomplete += 1
  })

  return Array.from(map.values())
    .map((r) => ({
      ...r,
      completionRate: r.total ? (r.completed / r.total) * 100 : 0,
    }))
    .sort((a,b)=>b.completionRate - a.completionRate || b.total - a.total)
}


function formatImportDate(value){
  if(!value) return 'Advisor Ranker: Not imported yet'
  const d = new Date(value)
  if(Number.isNaN(d.getTime())) return 'Advisor Ranker: Not imported yet'
  return `Advisor Ranker Updated: ${d.toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}`
}

