function MiniLineChart({ records = [] }) {
  const trend = buildFollowupTrend(records)
  const chartWidth = 640
  const chartHeight = 170
  const padX = 20
  const padY = 18
  const maxValue = Math.max(1, ...trend.map(d => Math.max(d.total, d.completed)))
  const usableW = chartWidth - padX * 2
  const usableH = chartHeight - padY * 2

  const pointFor = (item, index, key) => {
    const x = trend.length <= 1 ? chartWidth / 2 : padX + (index / (trend.length - 1)) * usableW
    const y = chartHeight - padY - (item[key] / maxValue) * usableH
    return `${x.toFixed(1)},${y.toFixed(1)}`
  }

  const completedPoints = trend.map((d,i)=>pointFor(d,i,'completed')).join(' ')
  const totalPoints = trend.map((d,i)=>pointFor(d,i,'total')).join(' ')
  const fillPoints = completedPoints ? `${padX},${chartHeight-padY} ${completedPoints} ${chartWidth-padX},${chartHeight-padY}` : ''

  const labels = trend.filter((_,i)=>i===0 || i===Math.floor(trend.length/2) || i===trend.length-1)

  return <div>
    <div className="chart-legend">
      <span><i className="legend-dot completed"></i>Completed</span>
      <span><i className="legend-line"></i>Created / Total</span>
    </div>
    <svg className="mockup-chart" viewBox={`0 0 ${chartWidth} ${chartHeight}`} preserveAspectRatio="none">
      <defs>
        <linearGradient id="realLineFill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#8b5cf6" stopOpacity=".48"/>
          <stop offset="100%" stopColor="#8b5cf6" stopOpacity="0"/>
        </linearGradient>
      </defs>
      {[0,.25,.5,.75,1].map((pct)=>(
        <line key={pct} x1="20" x2="620" y1={padY + pct * usableH} y2={padY + pct * usableH} stroke="rgba(255,255,255,.06)" />
      ))}
      {fillPoints && <polygon points={fillPoints} fill="url(#realLineFill)"/>}
      {totalPoints && <polyline points={totalPoints} fill="none" stroke="rgba(255,255,255,.55)" strokeWidth="2" strokeDasharray="6 7"/>}
      {completedPoints && <polyline points={completedPoints} fill="none" stroke="#a855f7" strokeWidth="3"/>}
    </svg>
    <div className="chart-date-labels">
      {labels.map((d)=><span key={d.date}>{shortDateLabel(d.date)}</span>)}
    </div>
  </div>
}

