function metricNumber(value){
  if(value === '-' || value === '' || value === null || value === undefined) return null
  const n = Number(String(value).replace('%','').replace(',','').trim())
  return Number.isFinite(n) ? n : null
}

function gradeFromNps(nps){
  const n = Number(nps ?? 0)
  if(n >= 90) return 'A+'
  if(n >= 80) return 'A'
  if(n >= 70) return 'B'
  if(n >= 60) return 'C'
  if(n >= 40) return 'D'
  return 'F'
}

function parseMetricsPerformanceWorkbook(workbook){
  const ws = workbook.Sheets['Table1'] || workbook.Sheets[workbook.SheetNames[0]]
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  if(!raw.length) return []

  const headers = raw[0].map(h => String(h ?? '').trim())
  const metricRows = new Map()

  raw.slice(1).forEach((row) => {
    const metric = String(row[0] ?? '').trim()
    if(metric) metricRows.set(metric.toLowerCase(), row)
  })

  const getMetric = (metricName, colIndex) => {
    const row = metricRows.get(metricName.toLowerCase())
    return row ? metricNumber(row[colIndex]) : null
  }

  const advisorCols = headers
    .map((name, index) => ({ name, index }))
    .filter(({ name }) => {
      const upper = name.toUpperCase()
      if(!name) return false
      if(['TOP 25%','NATIONAL','CE','CE04','ACCOUNTING'].includes(upper)) return false
      if(upper.includes('MO027') || upper.includes('NAPLETON')) return false
      return upper.includes(' ')
    })

  return advisorCols.map(({ name, index }) => ({
    advisor: canonicalAdvisorName(name),
    sample_size: getMetric('Sample Size (Main Survey)', index) ?? 0,
    final_nps: getMetric('SVS Final Net Promoter Score', index) ?? 0,
    issue_rate: getMetric(' Yes, I have an issue or concern I would like resolved', index) ?? 0,
    no_issue_rate: getMetric(' No', index) ?? 0,
    optional_sample_size: getMetric('Sample Size (Optional Survey)', index),
    initiation_rating: getMetric('Service Initiation Rating (1-10)', index),
    consultant_rating: getMetric('Service Consultant Rating (1-10)', index),
    facility_rating: getMetric('Service Facility Rating (1-10)', index),
    quality_rating: getMetric('Service Quality Rating (1-10)', index),
    pickup_rating: getMetric('Service Pick-Up/Wrap Up Rating (1-10)', index),
    grade: gradeFromNps(getMetric('SVS Final Net Promoter Score', index) ?? 0),
  }))
}

function AdvisorMetricsPerformanceTable({ rows = [] }){
  const [sortConfig, setSortConfig] = useState({ key: 'final_nps', direction: 'desc' })

  function handleSort(key){
    setSortConfig((current) => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }))
  }

  const sortedRows = useMemo(() => {
    return [...rows].sort((a,b) => {
      const av = a[sortConfig.key]
      const bv = b[sortConfig.key]
      const an = Number(av)
      const bn = Number(bv)
      if(Number.isFinite(an) && Number.isFinite(bn)) return sortConfig.direction === 'asc' ? an - bn : bn - an
      const result = String(av ?? '').localeCompare(String(bv ?? ''), undefined, { numeric: true, sensitivity: 'base' })
      return sortConfig.direction === 'asc' ? result : -result
    })
  }, [rows, sortConfig])

  const top = sortedRows[0]
  const needsAttention = [...rows].sort((a,b)=>Number(a.final_nps ?? 0)-Number(b.final_nps ?? 0))[0]
  const totalSurveys = rows.reduce((sum,r)=>sum + Number(r.sample_size || 0), 0)

  return <div className="panel metrics-performance-panel">
    <div className="panel-head">
      <div>
        <div className="panel-title"><BarChart3 size={17}/> Advisor Metrics Performance</div>
        <div className="small">Imported from Kia Metrics Performance Excel</div>
      </div>
    </div>

    <div className="metrics-summary-row">
      <div><span>Top Performer</span><b>{top?.advisor ?? '—'}</b></div>
      <div><span>Highest NPS</span><b className="green">{top?.final_nps ?? '—'}</b></div>
      <div><span>Needs Attention</span><b className="red">{needsAttention?.advisor ?? '—'}</b></div>
      <div><span>Total Surveys</span><b>{totalSurveys}</b></div>
    </div>

    <div className="table-wrap">
      <table>
        <thead>
          <tr>
            <th><SortHeader label="Advisor" column="advisor" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Survey Count" column="sample_size" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Final NPS" column="final_nps" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Issue %" column="issue_rate" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="No Issue %" column="no_issue_rate" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Consultant Rating" column="consultant_rating" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Quality Rating" column="quality_rating" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Grade" column="grade" sortConfig={sortConfig} onSort={handleSort}/></th>
          </tr>
        </thead>
        <tbody>
          {sortedRows.length === 0 ? <tr><td colSpan="8" className="small">No metrics performance report uploaded yet. Go to Management and upload the Metrics Performance Excel.</td></tr> : sortedRows.map((r)=>(
            <tr key={r.advisor}>
              <td><b>{r.advisor}</b></td>
              <td>{r.sample_size}</td>
              <td className={Number(r.final_nps) >= 80 ? 'green' : Number(r.final_nps) >= 60 ? 'orange' : 'red'}>{r.final_nps}</td>
              <td className={Number(r.issue_rate) > 0 ? 'orange' : 'green'}>{r.issue_rate}%</td>
              <td className="green">{r.no_issue_rate}%</td>
              <td>{r.consultant_rating ?? '—'}</td>
              <td>{r.quality_rating ?? '—'}</td>
              <td><span className={`grade-pill grade-${gradeFromNps(r.final_nps).replace('+','plus').toLowerCase()}`}>{gradeFromNps(r.final_nps)}</span></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  </div>
}


function cleanMoney(value){
  if(value === null || value === undefined || value === '') return null
  const n = Number(String(value).replace(/[$,]/g,'').trim())
  return Number.isFinite(n) ? n : null
}

function parseCdkDate(value){
  return excelDateToIso(value)
}

function parseCdkRepairPreinvoiceWorkbook(workbook){
  const repairSheet = workbook.Sheets['Repair Orders']
  const preInvoiceSheet = workbook.Sheets['Pre-Invoice']

  const repairRowsRaw = repairSheet ? XLSX.utils.sheet_to_json(repairSheet, { header: 1, defval: '' }) : []
  const repairHeaderIndex = repairRowsRaw.findIndex(row => String(row[0]).trim() === 'RO' && String(row[2]).trim() === 'Customer')
  const repairHeaders = repairHeaderIndex >= 0 ? repairRowsRaw[repairHeaderIndex] : []
  const repairRows = repairHeaderIndex >= 0
    ? repairRowsRaw.slice(repairHeaderIndex + 1).map(row => {
        const obj = {}
        repairHeaders.forEach((h,i)=>{ if(h) obj[String(h).trim()] = row[i] })
        return obj
      })
    : []

  const preRows = preInvoiceSheet ? XLSX.utils.sheet_to_json(preInvoiceSheet, { defval: '' }) : []

  return {
    repairOrders: repairRows.map((r) => ({
      ro: String(r['RO'] ?? '').trim().replace(/\.0$/, ''),
      tag: String(r['Tag'] ?? '').trim(),
      customer: String(r['Customer'] ?? '').trim(),
      model: String(r['Model'] ?? '').trim(),
      year: r['Year'] ? Number(r['Year']) : null,
      promise_date: parseCdkDate(r['Promise Date']),
      status: String(r['Status'] ?? '').trim(),
      advisor: titleCaseAdvisor(r['Advisor'] ?? ''),
      tech: titleCaseAdvisor(r['Tech'] ?? ''),
      notes: String(r['Notes'] ?? '').trim(),
    })).filter(r => r.ro || r.customer),

    preInvoices: preRows.map((r) => ({
      ro: String(r['RO'] ?? '').trim().replace(/\.0$/, ''),
      customer: String(r['Customer'] ?? '').trim(),
      age: r['Age'] === '' ? null : Number(r['Age']),
      model: String(r['Model'] ?? '').trim(),
      year: r['Year'] ? Number(r['Year']) : null,
      status_desc: String(r['Status Desc'] ?? '').trim(),
      advisor: titleCaseAdvisor(r['Advisor'] ?? ''),
      tech: titleCaseAdvisor(r['Tech'] ?? ''),
      invoice_amount: cleanMoney(r['Invoice $']),
      ro_estimate: cleanMoney(r['RO Estimate']),
      notes: String(r['Notes'] ?? '').trim(),
    })).filter(r => r.ro || r.customer),
  }
}

