  const committedRows = followRows.filter(r => String(r.status || r.commitment_status || '').toLowerCase().includes('committed'))
  const completeRows = followRows.filter(r => String(r.status || '').toLowerCase().includes('complete'))
  const issueRows = followRows.filter(r => String(r.status || '').toLowerCase().includes('issue'))
