function IsolatedCsiPerformanceView({ stats = {}, advisors = [] }) {
  const safeAdvisors = Array.isArray(advisors) ? advisors : []
  const store = Number(stats?.nps_score ?? 0)
  const region = Number(stats?.region_score ?? 0)
  const national = Number(stats?.national_score ?? 0)
  const completed = Number(stats?.complete ?? 0)
  const committed = Number(stats?.committed ?? 0)
  const issues = Number(stats?.issues ?? 0)
  const total = Number(stats?.followup_total ?? 0)
  const completedPct = total ? ((completed / total) * 100).toFixed(1) : '0.0'
  const committedPct = total ? ((committed / total) * 100).toFixed(1) : '0.0'

  const csiCards = [
    ['Store NPS', store.toFixed(2), store >= 83 ? 'green' : store >= 70 ? 'orange' : 'red'],
    ['Region', region.toFixed(2), 'blue'],
    ['National', national.toFixed(2), 'purple'],
    ['Completed %', `${completedPct}%`, Number(completedPct) >= 80 ? 'green' : 'orange'],
    ['Committed %', `${committedPct}%`, 'blue'],
    ['Issues', issues, issues > 0 ? 'red' : 'green'],
  ]

  return (
    <div className="csi-performance-page">
      <div className="csi-gauge-grid">
        {csiCards.map(([label, value, tone]) => (
          <div className="gauge-card" key={label}>
            <div className="gauge-title">{label}</div>
            <div className={`gauge-ring ${tone}`} style={{'--pct':'70%'}}>
              <div className="gauge-inner">
                <div className={`gauge-value ${tone}`}>{value}</div>
                <div className="gauge-sub">Current</div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="panel">
        <div className="panel-head">
          <div>
            <div className="panel-title">Advisor CSI Rankings</div>
            <div className="small">CSI Performance view only. Use Advisor Rankings tab for drill-downs.</div>
          </div>
        </div>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Advisor</th>
                <th>NPS / CSI</th>
                <th>Completed</th>
                <th>Committed</th>
                <th>Unresponsive</th>
                <th>Issues</th>
              </tr>
            </thead>
            <tbody>
              {safeAdvisors.map((a) => (
                <tr key={a.advisor}>
                  <td><button className="advisor-link" onClick={()=>onAdvisorClick?.(a)}>{a.advisor}</button></td>
                  <td className={Number(a.nps_score || 0) >= 83 ? 'green' : Number(a.nps_score || 0) >= 70 ? 'orange' : 'red'}>
                    {Number(a.nps_score || 0).toFixed(2)}
                  </td>
                  <td>{a.completed_surveys ?? 0}</td>
                  <td>{a.committed ?? 0}</td>
                  <td>{a.unresponsive ?? 0}</td>
                  <td>{a.issues ?? 0}</td>
                </tr>
              ))}
              {safeAdvisors.length === 0 && (
                <tr><td colSpan="6" className="small">No advisor CSI data loaded yet.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  )
}



function advisorAlias(value){
  const raw = titleCaseAdvisor(value)
  const key = raw.toLowerCase()
  const map = {
    toren: 'Toren Hamilton',
    liam: 'Liam Weisbrodt',
    lane: 'Lane Depriest',
    stanley: 'Stanley Snyder',
    garrett: 'Garrett Willey',
    morgan: 'Morgan Farrell',
    billy: 'Billy Greenhaw',
  }
  return map[key] || raw
}

function parseRentalDays(value){
  if(value === null || value === undefined || value === '') return null
  if(String(value).toLowerCase().includes('today')) return 0
  const n = Number(value)
  return Number.isFinite(n) ? n : null
}


function cleanCurrencyNumber(value){
  if(value === null || value === undefined || value === '') return null
  const n = Number(String(value).replace(/[$,% ,]/g,'').trim())
  return Number.isFinite(n) ? n : null
}

function salesAdvisorName(value){
  let raw = String(value || '').trim()
  if(raw.includes(',')){
    const [last, first] = raw.split(',').map(x=>x.trim()).filter(Boolean)
    if(first && last) raw = `${first} ${last}`
  }
  raw = raw.replace(/\bStan\b/i, 'Stanley')
  return titleCaseAdvisor(raw)
}

function parseAdvisorSalesSheet(workbook, sheetName, monthLabel){
  const ws = workbook.Sheets[sheetName]
  if(!ws) return []
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })
  return rows.map((r)=>({
    month_label: monthLabel,
    advisor: salesAdvisorName(r['Advisor']),
    ros: cleanCurrencyNumber(r['ROs']),
    sold_hours: cleanCurrencyNumber(r['Sold Hrs']),
    warranty_gp: cleanCurrencyNumber(r['Warr GP']),
    parts_gp: cleanCurrencyNumber(r['Parts GP']),
    total_warranty_gp: cleanCurrencyNumber(r['Tot Warr GP']),
    labor_gp_percent: cleanCurrencyNumber(r['Labor GP%']),
    parts_gp_percent: cleanCurrencyNumber(r['Parts GP%']),
    gp_percent: cleanCurrencyNumber(r['GP%']),
    customer_pay_gp: cleanCurrencyNumber(r['GP$'] ?? r['GPcpV$']),
    elr: cleanCurrencyNumber(r['ELR']),
    avg_cp_hours_ro: cleanCurrencyNumber(r['Avg CP Hrs/RO']),
    avg_hours_ro: cleanCurrencyNumber(r['Avg Hrs/RO']),
  })).filter(r => r.advisor && r.ros !== null)
}

function parseAdvisorProjectionSheet(workbook){
  const ws = workbook.Sheets['June Projection']
  if(!ws) return []
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })
  return rows.map((r)=>({
    advisor: salesAdvisorName(r['Advisor']),
    projected_ros: cleanCurrencyNumber(r['Projected ROs']),
    projected_sold_hours: cleanCurrencyNumber(r['Projected Sold Hrs']),
    projected_warranty_gp: cleanCurrencyNumber(r['Projected Warr GP']),
    projected_parts_gp: cleanCurrencyNumber(r['Projected Parts GP']),
    projected_total_warranty_gp: cleanCurrencyNumber(r['Projected Total Warr GP']),
    projected_customer_pay_gp: cleanCurrencyNumber(r['Projected GP$']),
  })).filter(r => r.advisor)
}

function parseAdvisorSalesSummaryWorkbook(workbook){
  const june = parseAdvisorSalesSheet(workbook, 'June MTD', 'June MTD')
  const may = parseAdvisorSalesSheet(workbook, 'May MTD', 'May MTD')
  const projections = parseAdvisorProjectionSheet(workbook)
  const projectionMap = new Map(projections.map(p => [normalizeAdvisorMatchName(p.advisor), p]))
  const combined = [...june, ...may].map(row => {
    const projection = row.month_label === 'June MTD' ? projectionMap.get(normalizeAdvisorMatchName(row.advisor)) : null
    return projection ? {...row, ...projection} : row
  })
  return combined.filter(r => ['Toren Hamilton','Lane Depriest','Liam Weisbrodt','Stanley Snyder','Garrett Willey'].some(a => isSameAdvisorName(a, r.advisor)))
}

function getLatestSalesRows(rows = [], advisorFilter = ''){
  const filtered = advisorFilter ? rows.filter(r => isSameAdvisorName(r.advisor, advisorFilter)) : rows
  const june = filtered.filter(r => r.month_label === 'June MTD')
  return june.length ? june : filtered.filter(r => r.month_label === 'May MTD')
}

function money(value){
  return `$${Number(value || 0).toLocaleString(undefined,{maximumFractionDigits:0})}`
}

function parseRentalsWorkbook(workbook){
  const ws = workbook.Sheets[workbook.SheetNames[0]]
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })
  return rows.map((r)=>({
    customer: String(r['CUSTOMER NAME'] ?? '').trim(),
    advisor: advisorAlias(r['ADVISOR'] ?? ''),
    ro: String(r['RO #'] ?? '').trim().replace(/\.0$/,''),
    date_out: excelDateToIso(r['DATE '] ?? r['DATE'] ?? ''),
    days_in_rental: parseRentalDays(r['DAY IN RENTAL']),
    days_in_service: parseRentalDays(r['DAY IN SERVICE']),
    warr: String(r['WARR'] ?? '').trim(),
    ex_warr: String(r['EX WARR'] ?? '').trim(),
    pay: String(r['PAY'] ?? '').trim(),
    stock: String(r['STOCK #'] ?? '').trim(),
    notes: '',
  })).filter(r => r.customer || r.ro || r.stock)
}

