function parseWarrantyAdjustmentsWorkbook(workbook){
  const ws = workbook.Sheets[workbook.SheetNames[0]]
  const matrix = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  const headerIndex = matrix.findIndex(row => String(row[0]).trim().toUpperCase() === 'ACCOUNT' && String(row[2]).trim().toUpperCase() === 'CONTROL')
  const rows = headerIndex >= 0 ? matrix.slice(headerIndex + 1) : []
  return rows.map((row)=> {
    const advisorId = String(row[7] ?? '').trim()
    const techId = String(row[8] ?? '').trim()
    return {
      debit_account: String(row[0] ?? '').trim(),
      debit_amount: cleanMoney(row[1]),
      control: String(row[2] ?? '').trim().replace(/\.0$/,''),
      description: String(row[3] ?? '').trim(),
      credit_account: String(row[4] ?? '').trim(),
      credit_amount: cleanMoney(row[5]),
      advisor_id: advisorId,
      advisor: advisorIdMap(advisorId),
      tech_id: techId,
      tech: techId,
      tech_time: row[9] === '' ? null : Number(row[9]),
      adjustment_amount: cleanMoney(row[10]),
      notes: String(row[11] ?? '').trim(),
      category: String(row[13] ?? '').trim(),
    }
  }).filter(r => r.control || r.description || r.adjustment_amount)
}

